INSERT INTO disease VALUES (1,'Common Cold','Viral upper respiratory infection causing runny nose, sore throat, and cough.');
INSERT INTO disease VALUES (2,'Influenza','Respiratory viral infection with fever, body aches, cough, and fatigue.');
INSERT INTO disease VALUES (3,'Asthma','Chronic airway inflammation causing wheezing, breathlessness, and coughing.');
INSERT INTO disease VALUES (4,'Hypertension','Persistently elevated blood pressure increasing cardiovascular risk.');
INSERT INTO disease VALUES (5,'Type 2 Diabetes','Metabolic disorder causing high blood glucose due to insulin resistance.');
INSERT INTO disease VALUES (6,'Tuberculosis','Bacterial infection primarily affecting lungs causing cough, fever, weight loss.');
INSERT INTO disease VALUES (7,'Malaria','Parasitic disease transmitted by mosquitoes causing fever and chills.');
INSERT INTO disease VALUES (8,'Pneumonia','Lung infection causing fever, cough, chest pain, and breathing difficulty.');
INSERT INTO disease VALUES (9,'Appendicitis','Inflammation of the appendix causing abdominal pain and fever.');
INSERT INTO disease VALUES (10,'Migraine','Recurrent severe headaches often with nausea and light sensitivity.');
INSERT INTO disease VALUES (11,'Anemia','Condition with reduced red blood cells causing fatigue and weakness.');
INSERT INTO disease VALUES (12,'COVID-19','Respiratory viral infection caused by SARS-CoV-2.');
INSERT INTO disease VALUES (13,'Chronic Kidney Disease','Progressive loss of kidney function over time.');
INSERT INTO disease VALUES (14,'Coronary Artery Disease','Narrowing of coronary arteries leading to reduced blood supply to heart.');
INSERT INTO disease VALUES (15,'Gastroenteritis','Infection causing diarrhea, vomiting, and abdominal cramps.');
INSERT INTO disease VALUES (16,'Dengue Fever','Viral infection transmitted by mosquitoes causing high fever and joint pain.');
INSERT INTO disease VALUES (17,'Meningitis','Inflammation of membranes around brain and spinal cord.');
INSERT INTO disease VALUES (18,'Osteoarthritis','Degenerative joint disease causing pain and stiffness.');
INSERT INTO disease VALUES (19,'Peptic Ulcer Disease','Sores in stomach lining often due to H. pylori infection.');
INSERT INTO disease VALUES (20,'Cancer','Malignant tumor in lung tissue affecting breathing and health.');
INSERT INTO medical_procedure VALUES (1,'Appendectomy','Surgery','Surgical removal of the appendix', TRUE);
INSERT INTO medical_procedure VALUES (2,'Coronary Angioplasty','Cardiology Procedure','Procedure to open blocked coronary arteries using a balloon or stent', TRUE);
INSERT INTO medical_procedure VALUES (3,'Caesarean Section','Surgery','Surgical delivery of a baby through the abdomen and uterus', TRUE);
INSERT INTO medical_procedure VALUES (4,'Coronary Artery Bypass Grafting','Cardiac Surgery','Surgery to improve blood flow to the heart by bypassing blocked arteries', TRUE);
INSERT INTO medical_procedure VALUES (5,'Gallbladder Removal (Cholecystectomy)','Surgery','Surgical removal of the gallbladder', TRUE);
INSERT INTO medical_procedure VALUES (6,'Knee Replacement','Orthopedic Surgery','Replacement of a damaged knee joint with an artificial joint', TRUE);
INSERT INTO medical_procedure VALUES (7,'Hip Replacement','Orthopedic Surgery','Surgical replacement of a damaged hip joint', TRUE);
INSERT INTO medical_procedure VALUES (8,'Bronchoscopy','Diagnostic Procedure','Procedure to examine the airways using a bronchoscope', TRUE);
INSERT INTO medical_procedure VALUES (9,'Endoscopy','Diagnostic Procedure','Procedure to examine the digestive tract using an endoscope', TRUE);
INSERT INTO medical_procedure VALUES (10,'Dialysis','Therapeutic Procedure','Process that removes waste and excess fluid from the blood when kidneys fail', TRUE);
INSERT INTO lab_test VALUES (1,'Complete Blood Count (CBC)','Measures red blood cells, white blood cells, hemoglobin, and platelets to detect infections, anemia, and inflammation.');
INSERT INTO lab_test VALUES (2,'Blood Glucose Test','Measures glucose levels in blood for diagnosing and monitoring diabetes.');
INSERT INTO lab_test VALUES (3,'HbA1c Test','Measures average blood sugar levels over the past 2ï¿½3 months.');
INSERT INTO lab_test VALUES (4,'Lipid Profile','Measures cholesterol and triglyceride levels to assess cardiovascular risk.');
INSERT INTO lab_test VALUES (5,'Liver Function Test (LFT)','Evaluates enzymes and proteins to assess liver damage or dysfunction.');
INSERT INTO lab_test VALUES (6,'Kidney Function Test (KFT)','Measures creatinine, urea, and other markers to assess kidney health.');
INSERT INTO lab_test VALUES (7,'Urinalysis','Examines urine to detect kidney disease, infection, and metabolic disorders.');
INSERT INTO lab_test VALUES (8,'Thyroid Function Test (TFT)','Measures thyroid hormones (TSH, T3, T4) to diagnose thyroid disorders.');
INSERT INTO lab_test VALUES (9,'C-Reactive Protein (CRP)','Measures inflammation levels in the body.');
INSERT INTO lab_test VALUES (10,'Erythrocyte Sedimentation Rate (ESR)','Measures inflammation by determining the rate at which red blood cells settle.');
INSERT INTO lab_test VALUES (11,'Blood Culture','Detects bacteria or fungi in blood to diagnose severe infections.');
INSERT INTO lab_test VALUES (12,'Sputum Smear Microscopy','Examines sputum samples for bacteria such as Mycobacterium tuberculosis.');
INSERT INTO lab_test VALUES (13,'GeneXpert Test','Molecular test detecting tuberculosis bacteria and drug resistance.');
INSERT INTO lab_test VALUES (14,'Chest X-ray','Imaging test used to detect lung infections or abnormalities.');
INSERT INTO lab_test VALUES (15,'Rapid Influenza Diagnostic Test','Detects influenza virus antigens from respiratory samples.');
INSERT INTO lab_test VALUES (16,'COVID-19 RT-PCR Test','Detects SARS-CoV-2 genetic material to confirm infection.');
INSERT INTO lab_test VALUES (17,'Rapid Antigen Test','Detects viral proteins for rapid diagnosis of respiratory infections.');
INSERT INTO lab_test VALUES (18,'Dengue NS1 Antigen Test','Detects dengue virus protein early in infection.');
INSERT INTO lab_test VALUES (19,'Malaria Blood Smear','Microscopic examination of blood to detect malaria parasites.');
INSERT INTO lab_test VALUES (20,'Rapid Malaria Antigen Test','Detects malaria parasite antigens in blood.');
INSERT INTO lab_test VALUES (21,'Troponin Test','Measures cardiac troponin proteins released during heart muscle damage.');
INSERT INTO lab_test VALUES (22,'Electrocardiogram (ECG)','Measures electrical activity of the heart to detect heart abnormalities.');
INSERT INTO lab_test VALUES (23,'Stress Test','Evaluates heart performance under physical stress.');
INSERT INTO lab_test VALUES (24,'Endoscopy','Visual examination of the stomach lining using a flexible camera.');
INSERT INTO lab_test VALUES (25,'H. pylori Test','Detects Helicobacter pylori bacteria responsible for stomach ulcers.');
INSERT INTO lab_test VALUES (26,'Lumbar Puncture with CSF Analysis','Examines cerebrospinal fluid to diagnose infections of the brain and spinal cord.');
INSERT INTO lab_test VALUES (27,'CT Scan','Detailed imaging technique used to detect internal abnormalities.');
INSERT INTO lab_test VALUES (28,'Abdominal Ultrasound','Uses sound waves to visualize organs such as the appendix or kidneys.');
INSERT INTO lab_test VALUES (29,'Biopsy','Removal of tissue sample to diagnose cancer or abnormal growths.');
INSERT INTO lab_test VALUES (30,'PET Scan','Advanced imaging used to detect cancer activity and spread.');
